const toScenarioStep = (step: any, scenario: any) => {
  if (step.op === "quote") {
    return {
      type: "quote",
      customer: { years: scenario.customer.yearsWithMHPCO },
      items: step.items,
    };
  }
  return {
    type: "claim",
    policy: step.policy,
    incident: step.incident,
  };
};

const input = readFileSync(0, "utf8");
const scenario = JSON.parse(input);
const steps = scenario.steps.map((step: any) => toScenarioStep(step, scenario));
const results = runScenario(steps);

